    // иҺ·еҸ– Csrf TokenпјҢд»ҘдҫҝиҝӣиЎҢж”¶и—ҸзӯүиҜ·жұӮ
    // иҺ·еҸ–ж–№жі•жқҘиҮӘи„ҡжң¬ Pixiv Previewer
    // https://github.com/Ocrosoft/PixivPreviewer
    // https://greasyfork.org/zh-CN/scripts/30766-pixiv-previewer/code
    u.getCsrfToken = function() {
        let pixivCsrfToken = getFromCache("pixivCsrfToken")
        if (!pixivCsrfToken) {
            let html = java.ajax("https://www.pixiv.net/")
            try {
                pixivCsrfToken = html.match(/token\\":\\"([a-z0-9]{32})/)[1]
                putInCache("pixivCsrfToken", pixivCsrfToken)  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…іпјҢж— жі•еӯҳеӮЁ nul
            } catch (e) {
                pixivCsrfToken = null
                cache.delete("pixivCsrfToken")  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…іпјҢж— жі•еӯҳеӮЁ nul
                // sleepToast("вҡ пёҸ жңӘзҷ»еҪ•иҙҰеҸ·(pixivCsrfToken)")
            }
            java.log(`pixivCsrfToken:\n${pixivCsrfToken}`)
        }
        return pixivCsrfToken
    }

