    u.combineNovels = function(novels) {
        return novels.filter(novel => {
            // еҚ•жң¬зӣҙжҺҘи§ЈжһҗдёәдёҖжң¬д№Ұ
            if (!novel.seriesId) {
                return true
            }
            // йӣҶеҗҲдёӯжІЎжңүиҜҘзі»еҲ—и§ЈжһҗдёәдёҖжң¬д№Ұ
            if (!seriesSet.has(novel.seriesId)) {
                seriesSet.add(novel.seriesId)
                return true
            }
            return false
        })
    }

