            java.log(`рҹҡ« еұҸи”ҪдҪңиҖ…IDпјҡ${JSON.stringify(blockAuthorList)}`)
            let blockAuthorSet = new Set(blockAuthorList.map(id => String(id)))
            novels = novels.filter(novel => !blockAuthorSet.has(String(novel.userId)))
        }
        return novels
    }


