        java.log(`рҹ‘Ө иҝҮж»ӨдҪңиҖ…пјҡ${inputAuthor.join("гҖҒ")}`)
        java.log(`рҹ‘Ө иҝҮж»ӨдҪңиҖ…пјҡиҝҮж»ӨеүҚ${novels0.length}пјӣиҝҮж»ӨеҗҺ${novels2.length}`)
    }
    return novels
}

