function login() {
    let resp = java.startBrowserAwait(`https://accounts.pixiv.net/login,
    {"headers": {"User-Agent": ${getWebViewUA()}}}`, 'зҷ»еҪ•иҙҰеҸ·', false)
    if (resp.code() === 200) {
        getCsrfToken(); getCookie()
        return true
    } else {
        java.log(resp.code()); sleepToast("рҹ…ҝпёҸ зҷ»еҪ•иҙҰеҸ·\n\nвҡ пёҸ зҷ»еҪ•еӨұиҙҘ")
        return false
    }
}

function logout() {
    removeCookie()
    java.startBrowser("https://www.pixiv.net/logout.php", "йҖҖеҮәиҙҰеҸ·")
    removeCookie(); removeLikeDataCache(); removeSettingsCache()
    sleepToast(`вң… е·ІйҖҖеҮәеҪ“еүҚиҙҰеҸ·\n\nйҖҖеҮәеҗҺиҜ·зӮ№еҮ»еҸідёҠи§’зҡ„ вң”пёҸ йҖҖеҮә\n\nзҷ»еҪ•иҜ·зӮ№еҮ»гҖҗзҷ»еҪ•иҙҰеҸ·гҖ‘иҝӣиЎҢзҷ»еҪ•`)
}

function removeCookie() {
    cookie.removeCookie('https://www.pixiv.net')
    cookie.removeCookie('https://accounts.pixiv.net')
    cookie.removeCookie('https://accounts.google.com')
    cookie.removeCookie('https://api.weibo.com')
    cache.delete("pixivCookie")
    cache.delete("pixiv:uid")
    cache.delete("pixivCsrfToken")  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…і
    cache.delete("headers")
}

function removeCacheList(listName) {
