// жӢҶеҲҶй•ҝиҜ„и®ә
function splitComments(text) {
    if (!text) return []
    let limit = 140

    // 1. йў„з•ҷеәҸеҸ·з©әй—ҙпјҲдҫӢеҰӮ " (10/10)" еҚ  8 дёӘеӯ—з¬ҰпјҢйў„з•ҷ 10 дёӘд»ҘйҳІдёҮдёҖпјү
    const reservedSpace = 10
    const safeLimit = limit - reservedSpace

    // 2. ж ёеҝғжӢҶеҲҶйҖ»иҫ‘
    let chars = Array.from(text.trim())
    let tempSegments = []

    const strongPunc = /[гҖӮпјҒпјҹвҖҰ\uff0e\uff01\uff1f!?.вҖҰ]/ // ејәж–ӯеҸҘж ҮзӮ№
    const weakPunc = /[\uff0c\uff1b,;]/                // ејұж–ӯеҸҘж ҮзӮ№

    while (chars.length > 0) {
        if (chars.length <= safeLimit) {
            tempSegments.push(chars.join('').trim())
            break
        }

        let chunk = chars.slice(0, safeLimit)
        let splitIndex = -1

        // дјҳе…Ҳзә§ 1: жҚўиЎҢз¬Ұ
        for (let i = chunk.length - 1; i >= 0; i--) {
            if (chunk[i] === '\n') {
                splitIndex = i
                break
            }
        }

        // дјҳе…Ҳзә§ 2: ејәж ҮзӮ№пјҲгҖӮпјҒпјҹзӯүпјү
        if (splitIndex === -1) {
            for (let i = chunk.length - 1; i >= 0; i--) {
                if (strongPunc.test(chunk[i])) {
                    splitIndex = i
                    break
                }
            }
        }

        // дјҳе…Ҳзә§ 3: ејұж ҮзӮ№пјҲд»…еңЁжІЎжүҫеҲ°ејәж ҮзӮ№ж—¶дҪҝз”ЁйҖ—еҸ·пјү
        if (splitIndex === -1) {
            for (let i = chunk.length - 1; i >= 0; i--) {
                if (weakPunc.test(chunk[i])) {
                    splitIndex = i
                    break
                }
            }
        }

        // е…ңеә•: зЎ¬жҲӘж–ӯ
        if (splitIndex === -1) {
            splitIndex = safeLimit - 1
        }

        // жҲӘеҸ–е№¶жё…зҗҶ
        let segment = chars.slice(0, splitIndex + 1).join('').trim();
        if (segment) tempSegments.push(segment)

        // з§»йҷӨе·ІеӨ„зҗҶеӯ—з¬Ұе№¶и·іиҝҮејҖеӨҙзҡ„з©әзҷҪ
        chars = chars.slice(splitIndex + 1);
        while (chars.length > 0 && (chars[0] === '\n' || chars[0] === ' ')) {
            chars.shift()
        }
    }

    // 3. жіЁе…ҘеәҸеҸ·
    const total = tempSegments.length;
    if (total <= 1) return tempSegments;
    return tempSegments.map((content, i) => `${content} (${i + 1}/${total})`).reverse();
}

