}

function removeCookie() {
    cookie.removeCookie('https://www.pixiv.net')
    cookie.removeCookie('https://accounts.pixiv.net')
    cookie.removeCookie('https://accounts.google.com')
    cookie.removeCookie('https://api.weibo.com')
    cache.delete("pixivCookie")
    cache.delete("pixiv:uid")
    cache.delete("pixivCsrfToken")  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…і
    cache.delete("headers")
}

function getCookie() {
    let pixivCookie = String(java.getCookie("https://www.pixiv.net/", null))
    if (isLogin()) putInCache("pixivCookie", pixivCookie, 60*60)
}

// иҺ·еҸ– Csrf TokenпјҢд»ҘдҫҝиҝӣиЎҢж”¶и—ҸзӯүиҜ·жұӮ
// иҺ·еҸ–ж–№жі•жқҘиҮӘи„ҡжң¬ Pixiv Previewer
// https://github.com/Ocrosoft/PixivPreviewer
// https://greasyfork.org/zh-CN/scripts/30766-pixiv-previewer/code
function getCsrfToken() {
    let pixivCsrfToken = getFromCache("pixivCsrfToken")
    if (!pixivCsrfToken) {
        let html = java.ajax("https://www.pixiv.net/")
        try {
            pixivCsrfToken = html.match(/token\\":\\"([a-z0-9]{32})/)[1]
            putInCache("pixivCsrfToken", pixivCsrfToken)  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…іпјҢж— жі•еӯҳеӮЁ nul
        } catch (e) {
            pixivCsrfToken = null
            cache.delete("pixivCsrfToken")  // дёҺзҷ»еҪ•и®ҫеӨҮжңүе…іпјҢж— жі•еӯҳеӮЁ nul
            // sleepToast("вҡ пёҸ жңӘзҷ»еҪ•иҙҰеҸ·(pixivCsrfToken)")
        }
        java.log(`pixivCsrfToken:\n${pixivCsrfToken}`)
    }
    return pixivCsrfToken
}

function getIllust() {}

function getPostBody(url, body, headers) {
    if (headers === undefined) headers = getFromCacheObject("headers")
    if (isJsonString(body)) {
        headers["content-type"] = "application/json; charset=utf-8"
    } else if (typeof body === "string") {
        headers["content-type"] = "application/x-www-form-urlencoded; charset=utf-8"
    }
    try {
        java.log(`getPostBody(${url}, ${body}, ${headers})`)
        return JSON.parse(java.post(url, body, headers).body())
    } catch (e) {
        e = String(e)
        // sleepToast(e)
        // sleepToast(JSON.stringify(headers))
        if (e.includes("400")) sleepToast(`рҹ“Ө getPostBody\n\nвҡ пёҸ зјәе°‘ headers`, 1)
        else if (e.includes("403")) sleepToast(`рҹ“Ө getPostBody\n\nвҡ пёҸ зјәе°‘ cookie жҲ– cookie иҝҮжңҹ`, 1)
        else if (e.includes("404")) sleepToast(`рҹ“Ө getPostBody\n\nвҡ пёҸ 404 зјәе°‘ pixivCsrfToken `, 1)
        else if (e.includes("422")) sleepToast(`рҹ“Ө getPostBody\n\nвҡ пёҸ иҜ·жұӮдҝЎжҒҜжңүиҜҜ`, 1)
        return {error: true, errMsg:e}
    }
}

