}

function editSettings(settingName) {
    let msg, status
    let settings = getFromCacheObject("pixivIllustSettings")
    if (!settings) settings = setDefaultSettings()
    if (!!settings[settingName]) {
        status = settings[settingName] = !settings[settingName]
    } else {
        status = settings[settingName] = true
    }
    putInCacheObject("pixivIllustSettings", settings)

    if (settingName === "IPDirect") {
        if (settings.IPDirect && !isLogin()) {
            msg = "вңҲпёҸ зӣҙиҝһжЁЎејҸ\n\nвңҲпёҸ зӣҙиҝһжЁЎејҸ йңҖзҷ»еҪ•иҙҰеҸ·\nеҪ“еүҚжңӘзҷ»еҪ•иҙҰеҸ·пјҢзҺ°е·Іе…ій—ӯзӣҙиҝһжЁЎејҸ"
            settings.IPDirect = false
            checkSettings()
            putInCacheObject("pixivIllustSettings", settings)
        } else {
            checkSettings()
            msg = `\n\n${statusMsg(status)}гҖҖ${settingsName[settingName]}\n\n${getSettingStatus(settingName)}`
        }

    } else if (settingName === "QUALITY_REGULAR") {
        msg = `\n\n${statusMsg(status)}гҖҖ${settingsName[settingName]}\n\n`
        if (settings.QUALITY_REGULAR)
             msg += "еӣҫзүҮиҙЁйҮҸи®ҫзҪ®дёә regular "
        else msg += "еӣҫзүҮиҙЁйҮҸи®ҫзҪ®дёә original"

    } else {
        msg = `\n\n${statusMsg(status)}гҖҖ${settingsName[settingName]}`
    }
    sleepToast(msg)
}

