    // жӯЈеҲҷеҢ№й…ҚзҪ‘еқҖеҶ…е®№
    if (baseUrl.includes("/ranking") && (baseUrl.endsWith("json"))) {
        return handlerRanking()
    }
    if (baseUrl.includes("/ranking")) {
        return handlerRegexIllusts()
    }
    else {
