function getArtwork() {
    let resp = JSON.parse(result)
    if (resp.error === true) {
        return []
    }
    let name = String(java.get("key"))
    let page = Number(java.get("page"))
    java.log(urlIP(urlSearchArtwork(name, page)))
    putInCacheObject(urlIP(urlSearchArtwork(name, page)), resp, cacheSaveSeconds)  // еҠ е…Ҙзј“еӯҳ
    return resp.body.illustManga.data
}

function search(name, page) {
    let resp = getAjaxJson(urlIP(urlSearchArtwork(name, page)))
    java.log(urlIP(urlSearchArtwork(name, page)))
    if (resp.error === true || resp.total === 0) {
        return {"data": [], "total":0, "lastPage": 0}
    }
    return resp.body.illustManga
}

function getConvertArtwork() {
    let illusts = []
    let name = String(java.get("key"))
    let name1 = String(java.s2t(name))
    let name2 = String(java.t2s(name))
    if (name1 !== name) illusts = illusts.concat(search(name1, 1).data)
    if (name2 !== name) illusts = illusts.concat(search(name2, 1).data)
    return illusts
}

(() => {
    let artworks = []
    artworks = artworks.concat(getArtwork())
    if (util.settings.CONVERT_CHINESE) artworks = artworks.concat(getConvertArtwork())
    // java.log(JSON.stringify(artworks))
    // иҝ”еӣһз©әеҲ—иЎЁдёӯжӯўжөҒзЁӢ
    if (artworks.length === 0) {
        return []
    }
    return util.formatIllusts(util.handIllusts(artworks))
})()

ruleToc.chapterList:
@js:
var util = objParse(String(java.get("util")))

function objParse(obj) {
    return JSON.parse(obj, (n, v) => {
        if (isFunctionString(v)) {
            return eval(`(${v})`)
        }
        return v;
    })
}

function urlIllust(novelId){
    if (util.settings.SHOW_ORIGINAL_LINK) {
        return urlIllustUrl(novelId)
    } else {
        return urlIllustDetailed(novelId)
    }
}

function oneShotHandler(res) {
    return [{
        title: res.title.replace(RegExp(/^\s+|\s+$/g), ""),
        chapterUrl: urlIP(urlIllust(res.id)),
        chapterInfo: `${timeTextFormat(res.createDate)}`
    }]
}

function seriesHandler(res) {
    let limit = 12, total = 0, illusts = []
    let seriesId = res.seriesNavData.seriesId
    if (res.seriesId === undefined) {
        total = getAjaxJson(urlIP(urlSeriesDetailed(res.seriesNavData.seriesId))).body.page.total
    } else {
        total = res.total
    }
    util.debugFunc(() => {
        java.log(`жң¬зі»еҲ— ${seriesId} дёҖе…ұжңү${total}з« `);
    })

    //иҰҒзҲ¬еҸ–зҡ„жҖ»ж¬Ўж•°
    let max = (total / limit) + 1
    for (let page = 1; page < max; page++) {
        // java.log(urlIP(urlSeriesDetailed(seriesId, page)))
        res = getAjaxJson(urlIP(urlSeriesDetailed(seriesId, page))).body
        let illusts_id = res.page.series.map(item => item.workId)
        illusts = illusts.concat(res.thumbnails.illust.filter(illust => illusts_id.includes(illust.id)))
    }
    illusts.reverse().forEach(illust => {
        illust.title = illust.title.replace(RegExp(/^\s+|\s+$/g), "")
        illust.chapterUrl = urlIP(urlIllust(illust.id))
        illust.chapterInfo = timeTextFormat(illust.createDate)
    })
    // java.log(JSON.stringify(illusts))
    return illusts
}

(() => {
    let res = util.getIllustRes(result)
    if (res.seriesNavData !== null) {
        return seriesHandler(res)
    } else {
        return oneShotHandler(res)
    }
})()

